# Pass reference images of different pants types
response = claude.messages.create(
    messages=[{"role": "user", "content": [
        {"type": "image", "source": chinos_reference},
        {"type": "image", "source": jeans_reference},
        {"type": "image", "source": dress_pants_reference},
        {"type": "image", "source": unknown_pants},
        {"type": "text", "text": "What type of pants is in the last image?"}
    ]}]
)

# PDF → multi-page images → extraction
pdf_pages = convert_pdf_to_images('paper.pdf')  # 20 pages

# Send all pages to Claude
response = claude.messages.create(
    messages=[{"role": "user", "content": [
        *[{"type": "image", "source": page} for page in pdf_pages],
        {"type": "text", "text": "Extract all figures and their captions"}
    ]}]
)
